nction() if not autoOn or cd or not LP.Character or not LP.Character:FindFirstChild("HumanoidRootPart") then return end for _,p in ipairs(P:GetPlayers()) do if p~=LP and p.Character and p.Character:FindFirstChild("HumanoidRootPart") then if (LP.Character.HumanoidRootPart.Position-p.Character.HumanoidRootPart.Position).Magnitude<=dist_check then cd=true if Ev then pcall(function() Ev:FireServer() end) end task.wait(1.5) cd=false break end end end end)
